raw.docVisualBody = T("Moodboards, UI direction, color studies, layout standards, and brand language.", { "zh-CN": "情绪板、UI方向、色彩研究、布局标准与品牌语言。", "zh-TW": "情緒板、UI方向、色彩研究、布局標準與品牌語言。", ja: "ムードボード、UI方向性、色彩研究、レイアウト標準、ブランド言語。", ko: "무드보드, UI 방향, 색채 연구, 레이아웃 표준, 브랜드 언어.", fr: "Planches d'ambiance, direction UI, études de couleur, standards de mise en page et langage de marque.", de: "Moodboards, UI-Richtung, Farbstudien, Layout-Standards und Markensprache.", es: "Moodboards, dirección de UI, estudios de color, estándares de layout y lenguaje de marca.", ru: "Мудборды, направление UI, цветовые исследования, стандарты макетов и брендовый язык.", pt: "Moodboards, direção de UI, estudos de cor, padrões de layout e linguagem de marca.", it: "Moodboard, direzione UI, studi cromatici, standard di layout e linguaggio del brand.", nl: "Moodboards, UI-richting, kleurstudies, layout-standaarden en merk-taal.", pl: "Moodboardy, kierunek UI, studia kolorów, standardy układu i język marki.", tr: "Moodboardlar, UI yönü, renk çalışmaları, düzen standartları ve marka dili.", vi: "Bảng tâm trạng, hướng UI, nghiên cứu màu sắc, tiêu chuẩn bố cục và ngôn ngữ thương hiệu.", id: "Moodboard, arah UI, studi warna, standar tata letak, dan bahasa merek.", uk: "Мудборди, напрямок UI, колористичні студії, стандарти макетів та брендова мова.", el: "Moodboards, κατεύθυνση UI, μελέτες χρωμάτων, πρότυπα διάταξης και γλώσσα εμπορικού σήματος.", cs: "Moodboardy, směr UI, barevné studie, standardy rozvržení a jazyk značky.", sv: "Moodboards, UI-riktning, färgstudier, layoutstandarder och varumärkesspråk." });
