raw.gamesHeroSubtitle = T("A growing collection of browser-based games built by Hanazar Games. No install needed — click and play.", { "zh-CN": "由哈纳扎尔工作室打造的浏览器游戏合集。无需安装 — 点击即玩。", "zh-TW": "由哈納扎爾工作室打造的瀏覽器遊戲合集。無需安裝 — 點擊即玩。", ja: "Hanazar Games が構築したブラウザベースのゲーム集。インストール不要 — クリックしてプレイ。", ko: "Hanazar Games가 만든 브라우저 기반 게임 모음입니다. 설치 불필요 — 클릭하고 플레이하세요.", fr: "Une collection croissante de jeux basés sur navigateur construite par Hanazar Games. Pas d'installation nécessaire — cliquez et jouez.", de: "Eine wachsende Sammlung browserbasierter Spiele von Hanazar Games. Keine Installation nötig — klicken und spielen.", es: "Una colección creciente de juegos basados en navegador construidos por Hanazar Games. Sin instalación — haz clic y juega.", ru: "Растущая коллекция браузерных игр от Hanazar Games. Установка не требуется — нажми и играй.", pt: "Uma coleção crescente de jogos baseados em navegador construídos pela Hanazar Games. Sem instalação — clique e jogue." });
raw.gameTicTacToeTitle = T("Tic-Tac-Toe", { "zh-CN": "井字棋", "zh-TW": "井字棋", ja: "Tic-Tac-Toe", ko: "Tic-Tac-Toe", fr: "Tic-Tac-Toe", de: "Tic-Tac-Toe", es: "Tic-Tac-Toe", ru: "Крестики-нолики", pt: "Jogo da Velha" });
raw.gameTicTacToeDesc = T("Classic tic-tac-toe with a modern twist — includes Connect Four, Gomoku, custom boards, AI opponents, puzzle rush, tactics trainer, and full replay analysis.", { "zh-CN": "经典井字棋现代升级版 — 包含四连棋、五子棋、自定义棋盘、AI对手、速通挑战、战术训练与完整复盘分析。", "zh-TW": "經典井字棋現代升級版 — 包含四連棋、五子棋、自訂棋盤、AI對手、速通挑戰、戰術訓練與完整覆盤分析。", ja: "モダンな twist を加えたクラシック tic-tac-toe — 四目並べ、五目並べ、カスタムボード、AI対戦、パズルラッシュ、戦術トレーナー、完全なリプレイ分析を含む。", ko: "현대적인 변화를 더한 클래식 틱택토 — 사목, 오목, 사용자 정의 보드, AI 상대, 퍼즐 러시, 전술 트레이너 및 전체 리플레이 분석 포함.", fr: "Tic-tac-toe classique avec une touche moderne — inclut Puissance 4, Gomoku, plateaux personnalisés, adversaires IA, puzzle rush, entraîneur tactique et analyse complète des replays.", de: "Klassisches Tic-Tac-Toe mit modernem Twist — enthält Vier gewinnt, Gomoku, benutzerdefinierte Bretter, AI-Gegner, Puzzle-Rush, Taktik-Trainer und vollständige Replay-Analyse.", es: "Tic-tac-toe clásico con un giro moderno — incluye Conecta 4, Gomoku, tableros personalizados, oponentes de IA, puzzle rush, entrenador táctico y análisis completo de repeticiones.", ru: "Классические крестики-нолики с современным поворотом — включает четыре в ряд, гомоку, пользовательские доски, ИИ-противников, пазл-раш, тактический тренер и полный анализ повторов.", pt: "Jogo da velha clássico com um toque moderno — inclui Ligue 4, Gomoku, tabuleiros personalizados, oponentes de IA, puzzle rush, treinador tático e análise completa de replays." });
raw.gameMinesweeperTitle = T("Minesweeper", { "zh-CN": "扫雷", "zh-TW": "踩地雷", ja: "マインスイーパー", ko: "지뢰찾기", fr: "Démineur", de: "Minesweeper", es: "Buscaminas", ru: "Сапер", pt: "Campo Minado" });
raw.gameMinesweeperDesc = T("The timeless mine-clearing puzzle. Use logic and intuition to flag every mine without setting one off.", { "zh-CN": "永恒的扫雷解谜游戏。运用逻辑与直觉标记所有地雷，不要触发它们。", "zh-TW": "永恆的踩地雷解謎遊戲。運用邏輯與直覺標記所有地雷，不要觸發它們。", ja: "永遠のマイン除去パズル。論理と直感を使って、すべての地雷に旗を立てて爆発させないようにしましょう。", ko: "영원한 지뢰 제거 퍼즐입니다. 논리와 직관을 사용하여 모든 지뢰에 깃발을 꽂고 폭발시키지 마세요.", fr: "Le puzzle intemporel de déminage. Utilisez la logique et l'intuition pour signaler chaque mine sans en déclencher une.", de: "Das zeitlose Minenräum-Puzzle. Verwenden Sie Logik und Intuition, um jede Mine zu markieren, ohne eine auszulösen.", es: "El puzzle atemporal de desminado. Usa la lógica y la intuición para marcar cada mina sin detonar una.", ru: "Вневременная головоломка сапера. Используйте логику и интуицию, чтобы отметить каждую мину, не подорвав ее.", pt: "O puzzle atemporal de desativação de minas. Use lógica e intuição para marcar cada mina sem detonar uma." });
raw.game2048Title = T("3D 2048", { "zh-CN": "3D 2048", "zh-TW": "3D 2048", ja: "3D 2048", ko: "3D 2048", fr: "2048 3D", de: "3D 2048", es: "2048 3D", ru: "3D 2048", pt: "2048 3D" });
raw.game2048Desc = T("The classic number-merging game reimagined in three dimensions. Slide blocks in 3D space and reach 2048.", { "zh-CN": "经典数字合并游戏的三维重制版。在立体空间中滑动方块，合成2048。", "zh-TW": "經典數字合併遊戲的三維重製版。在立體空間中滑動方塊，合成2048。", ja: "3次元に再構想されたクラシックな数字合成ゲーム。立体空間でブロックをスライドさせて2048を目指しましょう。", ko: "3차원으로 재구상된 클래식 숫자 병합 게임입니다. 입체 공간에서 블록을 슬라이드하여 2048을 만드세요.", fr: "Le jeu classique de fusion de nombres réimaginé en trois dimensions. Faites glisser les blocs dans l'espace 3D et atteignez 2048.", de: "Das klassische Zahlen-Verschmelzungsspiel in drei Dimensionen neu erdacht. Schieben Sie Blöcke im 3D-Raum und erreichen Sie 2048.", es: "El clásico juego de fusión de números reimaginado en tres dimensiones. Desliza bloques en el espacio 3D y alcanza 2048.", ru: "Классическая игра слияния чисел, переосмысленная в трех измерениях. Сдвигайте блоки в 3D-пространстве и достигните 2048.", pt: "O clássico jogo de fusão de números reimaginado em três dimensões. Deslize blocos no espaço 3D e alcance 2048." });
