// Build final translations object
export const t = (() => {
  const result: Record<LangCode, Record<string, string>> = {} as any;
  const langs: LangCode[] = [
    "zh-CN", "zh-TW", "en", "ja", "ko", "fr", "de", "es", "ru", "pt",
    "it", "nl", "pl", "tr", "vi", "id", "uk", "el", "cs", "sv",
  ];
  for (const lang of langs) {
    result[lang] = {};
    for (const key of Object.keys(raw)) {
      const entry = raw[key];
      result[lang][key] = (entry as any)[lang] ?? entry.en;
    }
  }
  return result;
})();

export function getTranslation(lang: LangCode, key: string): string {
  return t[lang]?.[key] ?? t.en[key] ?? key;
}
